package com.oneil.wellness.walkplanner.calendar.provider.google;
import static org.junit.jupiter.api.Assertions.*;import static org.mockito.ArgumentMatchers.*;import static org.mockito.Mockito.*;import com.oneil.wellness.walkplanner.calendar.credential.ProviderCredentialStore;import com.oneil.wellness.walkplanner.calendar.model.*;import com.oneil.wellness.walkplanner.calendar.persistence.*;import java.net.URI;import java.time.Instant;import java.util.*;import org.junit.jupiter.api.Test;
class GoogleTokenServiceTest {
 @Test void refreshesExpiredTokenWithBoundedTransientRetry(){var fixture=new Fixture(new GoogleHttpTransport.Response(500,"{}"),new GoogleHttpTransport.Response(200,"{\"access_token\":\"new-access\",\"expires_in\":3600,\"token_type\":\"Bearer\"}"));assertEquals("new-access",fixture.service.accessToken());assertEquals(2,fixture.http.calls);verify(fixture.credentials).rotateSecret(fixture.connection.getId(),"access-token","new-access");assertEquals(CalendarConnectionStatus.CONNECTED,fixture.connection.getConnectionStatus());}
 @Test void revokedRefreshTokenRequiresAuthorizationWithoutInfiniteRetry(){var fixture=new Fixture(new GoogleHttpTransport.Response(400,"{\"error\":\"invalid_grant\"}"));var error=assertThrows(GoogleProviderException.class,fixture.service::accessToken);assertTrue(error.isAuthorizationRequired());assertEquals(1,fixture.http.calls);assertEquals(CalendarConnectionStatus.AUTHORIZATION_REQUIRED,fixture.connection.getConnectionStatus());}
 static class Fixture{final CalendarProviderConnection connection=new CalendarProviderConnection(CalendarProviderType.GOOGLE,"Google",true);final ProviderConnectionService connections=mock(ProviderConnectionService.class);final ProviderCredentialStore credentials=mock(ProviderCredentialStore.class);final OAuthTokenMetadataRepository metadata=mock(OAuthTokenMetadataRepository.class);final QueueHttp http;final GoogleTokenService service;Fixture(GoogleHttpTransport.Response...responses){http=new QueueHttp(responses);when(connections.find(CalendarProviderType.GOOGLE)).thenReturn(Optional.of(connection));when(credentials.readSecret(connection.getId(),"refresh-token")).thenReturn(Optional.of("refresh"));when(credentials.readSecret(connection.getId(),"access-token")).thenAnswer(i->Optional.of(http.calls<2?"old-access":"new-access"));var meta=new OAuthTokenMetadata(connection.getId(),Instant.now().minusSeconds(10),GoogleOAuthService.CALENDAR_LIST_SCOPE+" "+GoogleOAuthService.EVENT_SCOPE,"Bearer");when(metadata.findById(connection.getId())).thenReturn(Optional.of(meta));var config=new GoogleCalendarConfiguration();config.setClientId("client");config.setClientSecret("secret");config.setTokenUri(URI.create("https://oauth.test/token"));service=new GoogleTokenService(config,http,connections,credentials,metadata);}}
 static class QueueHttp implements GoogleHttpTransport{final Deque<Response> responses;int calls;QueueHttp(Response...r){responses=new ArrayDeque<>(List.of(r));}public Response exchange(String m,URI u,Map<String,String>h,String b){calls++;return responses.removeFirst();}}
}
